<template>
  <div class="websocket-advanced-tool">
    <el-card>
      <div slot="header">
        <span>WebSocket 高级测试</span>
        <el-tag v-if="backendAvailable" type="success" size="small" style="margin-left: 10px">后端可用</el-tag>
        <el-tag v-else type="danger" size="small" style="margin-left: 10px">后端不可用</el-tag>
      </div>

      <el-row :gutter="20">
        <el-col :span="8">
          <el-divider>连接设置</el-divider>
          <el-form label-width="80px">
            <el-form-item label="服务器">
              <el-radio-group v-model="serverType">
                <el-radio label="custom">自定义服务器</el-radio>
                <el-radio label="builtin" :disabled="!backendAvailable">内置服务器</el-radio>
              </el-radio-group>
            </el-form-item>

            <el-form-item label="WebSocket URL">
              <el-input v-model="wsUrl" placeholder="ws://localhost:8080/ws/client1" :disabled="serverType === 'builtin'">
                <template slot="prepend">
                  <el-select v-model="wsProtocol" style="width: 80px">
                    <el-option label="ws://" value="ws" />
                    <el-option label="wss://" value="wss" />
                  </el-select>
                </template>
              </el-input>
            </el-form-item>

            <el-form-item label="客户端ID">
              <el-input v-model="clientId" placeholder="客户端唯一标识" />
            </el-form-item>

            <el-form-item label="重连设置">
              <el-switch v-model="autoReconnect" active-text="自动重连" />
              <el-input-number v-model="reconnectInterval" :min="1000" :max="30000" :step="1000" style="width: 100px; margin-left: 10px" />
              <span style="margin-left: 5px">ms</span>
            </el-form-item>
          </el-form>

          <div class="connection-actions">
            <el-button type="primary" @click="connect" :disabled="connected" :loading="connecting">
              连接
            </el-button>
            <el-button type="danger" @click="disconnect" :disabled="!connected">
              断开
            </el-button>
            <el-button @click="clearMessages">清空消息</el-button>
          </div>

          <el-divider>连接状态</el-divider>
          <div class="status-panel">
            <div class="status-item">
              <span class="status-label">状态:</span>
              <el-tag :type="connected ? 'success' : 'danger'" size="small">
                {{ connected ? '已连接' : '未连接' }}
              </el-tag>
            </div>
            <div class="status-item">
              <span class="status-label">连接时间:</span>
              <span>{{ connectTime || '-' }}</span>
            </div>
            <div class="status-item">
              <span class="status-label">消息数量:</span>
              <span>{{ messages.length }}</span>
            </div>
            <div class="status-item">
              <span class="status-label">在线客户端:</span>
              <span>{{ onlineCount }}</span>
            </div>
          </div>
        </el-col>

        <el-col :span="16">
          <el-divider>消息列表</el-divider>
          <div class="message-list" ref="messageList">
            <div v-for="(msg, index) in messages" :key="index" :class="['message-item', msg.direction]">
              <div class="message-header">
                <el-tag :type="msg.direction === 'send' ? 'primary' : 'success'" size="mini">
                  {{ msg.direction === 'send' ? '发送' : '接收' }}
                </el-tag>
                <span class="message-time">{{ msg.time }}</span>
              </div>
              <div class="message-content">{{ msg.content }}</div>
            </div>
            <el-empty v-if="messages.length === 0" description="暂无消息" :image-size="60" />
          </div>

          <el-divider>发送消息</el-divider>
          <el-form label-width="80px">
            <el-form-item label="消息类型">
              <el-select v-model="messageType" style="width: 150px">
                <el-option label="文本" value="text" />
                <el-option label="JSON" value="json" />
                <el-option label="Ping" value="ping" />
              </el-select>
            </el-form-item>

            <el-form-item label="消息内容" v-if="messageType !== 'ping'">
              <el-input
                v-model="messageContent"
                type="textarea"
                :rows="3"
                :placeholder="messageType === 'json' ? '输入JSON格式消息' : '输入消息内容'"
              />
            </el-form-item>

            <el-form-item>
              <el-button type="primary" @click="sendMessage" :disabled="!connected">
                发送
              </el-button>
              <el-button @click="sendBroadcast" :disabled="!connected || serverType !== 'builtin'">
                广播消息
              </el-button>
              <el-button @click="sendEcho" :disabled="!connected || serverType !== 'builtin'">
                回显测试
              </el-button>
            </el-form-item>
          </el-form>

          <el-divider>快捷消息</el-divider>
          <div class="quick-messages">
            <el-tag v-for="msg in quickMessages" :key="msg" @click="sendQuickMessage(msg)" style="cursor: pointer; margin: 3px">
              {{ msg }}
            </el-tag>
          </div>
        </el-col>
      </el-row>
    </el-card>
  </div>
</template>

<script>
export default {
  name: 'WebSocketAdvancedTool',
  data() {
    return {
      serverType: 'custom',
      wsProtocol: 'ws',
      wsUrl: 'localhost:8080/ws',
      clientId: 'client_' + Date.now(),
      autoReconnect: true,
      reconnectInterval: 3000,
      connected: false,
      connecting: false,
      connectTime: '',
      messages: [],
      messageType: 'text',
      messageContent: '',
      onlineCount: 0,
      ws: null,
      reconnectTimer: null,
      backendAvailable: false,
      quickMessages: [
        'Hello',
        'Ping',
        '{"type": "test", "data": "hello"}',
        '{"type": "broadcast", "message": "大家好"}'
      ]
    }
  },
  computed: {
    fullWsUrl() {
      if (this.serverType === 'builtin') {
        return `${this.wsProtocol}://${window.location.host}/ws/${this.clientId}`
      }
      return `${this.wsProtocol}://${this.wsUrl}`
    }
  },
  mounted() {
    this.checkBackend()
  },
  beforeDestroy() {
    this.disconnect()
  },
  methods: {
    async checkBackend() {
      try {
        const response = await fetch('/api/ping')
        this.backendAvailable = response.ok
        if (this.backendAvailable) {
          this.serverType = 'builtin'
        }
      } catch (e) {
        this.backendAvailable = false
        this.serverType = 'custom'
      }
    },
    connect() {
      if (this.connected) return

      this.connecting = true
      this.clearReconnectTimer()

      try {
        this.ws = new WebSocket(this.fullWsUrl)

        this.ws.onopen = () => {
          this.connected = true
          this.connecting = false
          this.connectTime = new Date().toLocaleString()
          this.addMessage('system', 'WebSocket连接成功')
          this.$message.success('连接成功')
        }

        this.ws.onmessage = (event) => {
          try {
            const data = JSON.parse(event.data)
            this.addMessage('receive', event.data)
            
            if (data.type === 'connected') {
              this.clientId = data.clientId
            }
            if (data.onlineCount !== undefined) {
              this.onlineCount = data.onlineCount
            }
          } catch (e) {
            this.addMessage('receive', event.data)
          }
        }

        this.ws.onerror = (error) => {
          this.addMessage('system', 'WebSocket错误: ' + error)
          this.$message.error('连接错误')
        }

        this.ws.onclose = () => {
          this.connected = false
          this.connecting = false
          this.addMessage('system', 'WebSocket连接关闭')
          
          if (this.autoReconnect) {
            this.scheduleReconnect()
          }
        }
      } catch (e) {
        this.connecting = false
        this.$message.error('连接失败: ' + e.message)
      }
    },
    disconnect() {
      this.clearReconnectTimer()
      if (this.ws) {
        this.ws.close()
        this.ws = null
      }
      this.connected = false
    },
    scheduleReconnect() {
      this.reconnectTimer = setTimeout(() => {
        if (!this.connected) {
          this.addMessage('system', '尝试重新连接...')
          this.connect()
        }
      }, this.reconnectInterval)
    },
    clearReconnectTimer() {
      if (this.reconnectTimer) {
        clearTimeout(this.reconnectTimer)
        this.reconnectTimer = null
      }
    },
    sendMessage() {
      if (!this.connected || !this.messageContent) return

      let content = this.messageContent
      if (this.messageType === 'json') {
        try {
          JSON.parse(content)
        } catch (e) {
          this.$message.error('JSON格式错误')
          return
        }
      }

      this.ws.send(content)
      this.addMessage('send', content)
      this.messageContent = ''
    },
    sendPing() {
      if (!this.connected) return
      const pingMsg = JSON.stringify({ type: 'ping' })
      this.ws.send(pingMsg)
      this.addMessage('send', pingMsg)
    },
    sendBroadcast() {
      if (!this.connected) return
      const msg = this.messageContent || '广播消息'
      const broadcastMsg = JSON.stringify({ type: 'broadcast', message: msg })
      this.ws.send(broadcastMsg)
      this.addMessage('send', broadcastMsg)
    },
    sendEcho() {
      if (!this.connected) return
      const msg = this.messageContent || '回显测试'
      const echoMsg = JSON.stringify({ type: 'echo', message: msg })
      this.ws.send(echoMsg)
      this.addMessage('send', echoMsg)
    },
    sendQuickMessage(msg) {
      this.messageContent = msg
      this.messageType = msg.startsWith('{') ? 'json' : 'text'
      if (this.connected) {
        this.ws.send(msg)
        this.addMessage('send', msg)
      }
    },
    addMessage(direction, content) {
      this.messages.push({
        direction,
        content,
        time: new Date().toLocaleTimeString()
      })
      this.$nextTick(() => {
        const list = this.$refs.messageList
        if (list) {
          list.scrollTop = list.scrollHeight
        }
      })
    },
    clearMessages() {
      this.messages = []
    }
  }
}
</script>

<style scoped>
.websocket-advanced-tool {
  padding: 20px;
}

.connection-actions {
  text-align: center;
  margin: 20px 0;
}

.status-panel {
  background: #f5f7fa;
  border-radius: 8px;
  padding: 15px;
}

.status-item {
  display: flex;
  justify-content: space-between;
  padding: 8px 0;
  border-bottom: 1px solid #ebeef5;
}

.status-item:last-child {
  border-bottom: none;
}

.status-label {
  color: #909399;
}

.message-list {
  height: 300px;
  overflow-y: auto;
  background: #f5f7fa;
  border-radius: 8px;
  padding: 10px;
}

.message-item {
  margin-bottom: 10px;
  padding: 10px;
  border-radius: 8px;
  background: white;
}

.message-item.send {
  border-left: 3px solid #409EFF;
}

.message-item.receive {
  border-left: 3px solid #67C23A;
}

.message-item.system {
  border-left: 3px solid #E6A23C;
  background: #fdf6ec;
}

.message-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 5px;
}

.message-time {
  font-size: 12px;
  color: #909399;
}

.message-content {
  font-family: monospace;
  font-size: 13px;
  word-break: break-all;
  white-space: pre-wrap;
}

.quick-messages {
  display: flex;
  flex-wrap: wrap;
  gap: 5px;
}
</style>
